import React from 'react';
import {Card} from 'react-bootstrap';


// Componentes
import List from '../../Components/List'


// Importando do Redux
import { useSelector } from 'react-redux'



const itemsPerPage = 10

const Curso = (props) => {

    const listaInstituicoes = useSelector(state => state.listaInstituicoes)
    const instituicaoSelecionada = useSelector(state => state.instituicaoSelecionada)

    let filtered = useSelector(state => state.listaInstituicoesFiltrado)
    let cardTitle
    let pageTitle = 'Selecionar Instituição de Ensino Superior'

    if(instituicaoSelecionada !== ""){
        cardTitle = <Card.Title as="h5">Instituição selecionada: <b>{instituicaoSelecionada.NO_IES}</b>. Para trocar, escolha uma instituição abaixo.</Card.Title>
        pageTitle = "Trocar Instituição de Ensino Superior"
    }
    else
        cardTitle = <Card.Title as="h5">Selecione uma Instituição de Ensino Superior</Card.Title>
    
    return (
        <List
            pageTitle={pageTitle}
            cardTitle={cardTitle}
            placeholder="Pesquise por um curso de graduação"
            itemsPerPage={itemsPerPage}
            data={listaInstituicoes}
            dataFiltered={filtered}
            filterDispach='FILTER_IES'
            selectDispach='SELECT_IES'
            itemType='IES'
        />
    )
}


export default Curso;